import java.io.File;
import java.util.Scanner;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a file name: ");
        String fileName = scanner.nextLine();

        // Define the base directory where files should be located
        String baseDirectory = "/path/to/directory/";

        // Validate the input to prevent path traversal
        if (!fileName.contains("..")) {
            File file = new File(baseDirectory + fileName);

            try {
                if (file.getCanonicalPath().startsWith(baseDirectory) && file.exists()) {
                    System.out.println("File exists.");
                } else {
                    System.out.println("File does not exist.");
                }
            } catch (Exception e) {
                System.out.println("An error occurred: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file name.");
        }
    }

}

